-- ============================================================
-- Actores Electorales · Mapa de Colombia (Instagram por departamento)
-- Tabla analoga a content_manager_mapa_countries pero a nivel departamental.
-- Los valores de "nombre" coinciden (tras normalizar acentos/mayusculas) con
-- la propiedad NOMBRE_DPT del GeoJSON public/colombia-departamentos.geojson.
-- ============================================================

CREATE TABLE IF NOT EXISTS content_manager_actores_colombia (
    id              TEXT PRIMARY KEY,        -- Codigo DANE del departamento
    nombre          TEXT NOT NULL,           -- Nombre (match con NOMBRE_DPT del GeoJSON)
    capital         TEXT,
    lat             NUMERIC,
    lng             NUMERIC,
    tema            TEXT,
    keywords        JSONB DEFAULT '[]'::jsonb,
    sentimiento     TEXT,
    sentimiento_pct JSONB,                    -- {positivo, neutral, negativo}
    volumen         NUMERIC DEFAULT 0,        -- Menciones en Instagram
    plataformas     JSONB,                    -- {"Instagram": n}
    resumen         TEXT,
    tendencia       TEXT,                     -- 'sube' | 'estable' | 'baja'
    pct_cambio      NUMERIC DEFAULT 0,
    top_hashtags    JSONB DEFAULT '[]'::jsonb,
    update_time     TEXT
);

-- ---------- Seguridad (RLS) coherente con el resto del proyecto ----------
ALTER TABLE content_manager_actores_colombia ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Lectura abierta para autenticados" ON content_manager_actores_colombia;
CREATE POLICY "Lectura abierta para autenticados"
    ON content_manager_actores_colombia FOR SELECT TO authenticated USING (true);

DROP POLICY IF EXISTS "Escritura solo para admins" ON content_manager_actores_colombia;
CREATE POLICY "Escritura solo para admins"
    ON content_manager_actores_colombia FOR ALL TO authenticated
    USING (public.is_admin()) WITH CHECK (public.is_admin());

-- ---------- Datos semilla (33 departamentos) ----------
ON CONFLICT (id) DO NOTHING;
